{"report_type": "HTML", "html": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<style>
  @page { margin: 0; size: A4; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    font-family: Arial, Helvetica, sans-serif;
    font-size: 9pt;
    color: #1a1a2e;
    background: #fff;
  }
  .page {
    max-width: 820px;
    margin: 0 auto;
    padding: 28px 36px 36px;
  }

  /* HEADER */
  .hotel-logo { max-height: 52px; max-width: 95px; }
  .logo-box {
    display: inline-block; width: 46px; height: 46px;
    background: #1a1a2e; color: #fff;
    font-size: 16pt; font-weight: 700; text-align: center;
    line-height: 46px; border-radius: 5px;
  }
  .hotel-name { font-size: 14pt; font-weight: 700; color: #1a1a2e; }
  .hotel-sub { font-size: 7.5pt; color: #6b7280; margin-top: 2px; line-height: 1.5; }
  .doc-title { font-size: 13pt; font-weight: 700; color: #1a1a2e; }
  .doc-subtitle { font-size: 7pt; color: #6b7280; text-transform: uppercase; letter-spacing: 0.8px; margin-top: 2px; }
  .doc-ref { font-size: 8pt; color: #6b7280; margin-top: 6px; line-height: 1.7; }
  .doc-ref strong { color: #374151; }
  .header-divider { border: none; border-top: 2px solid #1a1a2e; margin: 14px 0 16px; }

  /* STATUS PILLS */
  .pill {
    display: inline-block; padding: 2px 9px; border-radius: 10px;
    font-size: 7pt; font-weight: 700; text-transform: uppercase;
    letter-spacing: 0.4px; margin-right: 5px;
    border: 1px solid #d1d5db; background: #f9fafb; color: #374151;
  }
  .pills-row { margin-bottom: 14px; }

  /* SECTION TITLE */
  .section-title {
    font-size: 7.5pt; font-weight: 700; color: #fff;
    text-transform: uppercase; letter-spacing: 0.6px;
    background: #1a1a2e;
    padding: 6px 9px;
    margin-top: 14px; margin-bottom: 8px;
  }

  /* COMPACT INFO TABLE */
  .info-table { width: 100%; border-collapse: collapse; margin-bottom: 4px; }
  .info-table td { padding: 4px 8px; font-size: 9pt; border-bottom: 1px solid #f1f5f9; vertical-align: middle; white-space: nowrap; }
  .info-table tr:last-child td { border-bottom: none; }
  .info-key { width: 22%; color: #1a1a2e; font-weight: 700; }
  .info-val { width: 28%; color: #1a1a2e; font-weight: 400; }

  /* ROOMS TABLE */
  .rooms-table { width: 100%; border-collapse: collapse; font-size: 8.5pt; margin-bottom: 4px; }
  .rooms-table thead tr { background: #1a1a2e; color: #fff; }
  .rooms-table thead th { padding: 6px 9px; text-align: left; font-size: 7pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.4px; }
  .rooms-table thead th.num { text-align: right; }
  .rooms-table tbody tr:nth-child(even) { background: #f9fafb; }
  .rooms-table tbody td { padding: 7px 9px; border-bottom: 1px solid #f1f5f9; color: #374151; }
  .rooms-table tbody td.num { text-align: right; }
  .rooms-table tfoot tr { border-top: 2px solid #1a1a2e; }
  .rooms-table tfoot td { padding: 7px 9px; font-weight: 700; color: #1a1a2e; font-size: 9pt; background: #f9fafb; }
  .rooms-table tfoot td.num { text-align: right; }

  /* PAYMENT SUMMARY */
  .payment-table { width: 55%; margin-left: 45%; border-collapse: collapse; margin-bottom: 4px; }
  .payment-table td { padding: 6px 10px; font-size: 9pt; border-bottom: 1px solid #f1f5f9; }
  .p-label { color: #6b7280; }
  .p-value { text-align: right; font-weight: 600; color: #1a1a2e; }
  .total-row td { background: #1a1a2e; color: #fff; font-weight: 700; font-size: 9.5pt; border: none; }
  .paid-row td { background: #f9fafb; color: #15803d; font-weight: 600; border: none; font-size: 8pt; }

  /* NOTES */
  .notes-box {
    border: 1px solid #e5e7eb; border-radius: 4px;
    padding: 8px 12px; font-size: 8.5pt; color: #374151; margin-bottom: 4px;
  }
  .notes-label { font-size: 6.5pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.6px; margin-bottom: 2px; color: #9ca3af; }

  /* FOOTER */
  .footer-divider { border: none; border-top: 1px solid #e5e7eb; margin: 20px 0 12px; }
  .footer-note { font-size: 7pt; color: #9ca3af; line-height: 1.7; }
  .footer-company { font-size: 9pt; font-weight: 700; color: #1a1a2e; }
  .footer-date { font-size: 7pt; color: #9ca3af; margin-top: 2px; }
  .sig-line { margin-top: 16px; border-top: 1px solid #e5e7eb; padding-top: 5px; font-size: 7pt; color: #9ca3af; text-align: center; }
</style>
</head>
<body>
<div class="page">

  <!-- HEADER -->
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="55%" valign="top">
        <table cellpadding="0" cellspacing="0">
          <tr>
            <td style="padding-right:10px;" valign="middle">
              {% if hotel_logo %}
                <img src="{{ hotel_logo }}" alt="{{ company }}" class="hotel-logo" />
              {% else %}
                <div class="logo-box">{{ (company or 'H')[:1] }}</div>
              {% endif %}
            </td>
            <td valign="middle">
              <div class="hotel-name">{{ company }}</div>
              <div class="hotel-sub">
                {% if hotel_tagline %}{{ hotel_tagline }}<br>{% endif %}
                {% if hotel_address %}{{ hotel_address }}<br>{% endif %}
                {% if hotel_phone %}{{ hotel_phone }}{% if hotel_email %} &middot; {% endif %}{% endif %}
                {% if hotel_email %}{{ hotel_email }}{% endif %}
              </div>
            </td>
          </tr>
        </table>
      </td>
      <td valign="top" align="right">
        <div class="doc-title">Reservation Confirmation</div>
        <div class="doc-subtitle">{{ reservation.reservation_type or 'Individual' }} Booking</div>
        <div class="doc-ref">
          <strong>Ref:</strong> {{ reservation.name }}<br>
          <strong>Generated:</strong> {{ generated_at }}
        </div>
      </td>
    </tr>
  </table>
  <hr class="header-divider" />

  <!-- STATUS PILLS -->
  <div class="pills-row">
    {% set rs = (reservation.reservation_status or '') | lower %}
    {% if rs == 'confirmed' %}<span class="pill">&#10003; Confirmed</span>
    {% elif rs == 'hold' %}<span class="pill">&#9679; On Hold</span>
    {% elif rs == 'cancelled' %}<span class="pill">&#10007; Cancelled</span>
    {% else %}<span class="pill">{{ reservation.reservation_status }}</span>{% endif %}
    {% set ps = (reservation.payment_status or '') | lower %}
    {% if ps == 'paid' %}<span class="pill">&#10003; Paid</span>
    {% elif ps == 'pending' %}<span class="pill">&#9679; Pending Payment</span>
    {% else %}<span class="pill">{{ reservation.payment_status }}</span>{% endif %}
    <span class="pill">{{ reservation.reservation_type or 'Individual' }}</span>
    {% if reservation.source_channel %}<span class="pill">{{ reservation.source_channel }}</span>{% endif %}
  </div>

  <!-- STAY DETAILS -->
  <div class="section-title">Stay Details</div>
  <table class="info-table" cellpadding="0" cellspacing="0">
    <colgroup>
      <col style="width:22%" /><col style="width:28%" />
      <col style="width:22%" /><col style="width:28%" />
    </colgroup>
    <tr>
      <td class="info-key">Check-In Date</td>
      <td class="info-val">{{ reservation.from_date }}</td>
      <td class="info-key">Check-Out Date</td>
      <td class="info-val">{{ reservation.to_date }}</td>
    </tr>
    <tr>
      <td class="info-key">Number of Nights</td>
      <td class="info-val">{{ reservation.number_of_nights }} night{% if reservation.number_of_nights != 1 %}s{% endif %}</td>
      <td class="info-key">Rooms Reserved</td>
      <td class="info-val">{{ reservation.rooms | length }} room{% if reservation.rooms | length != 1 %}s{% endif %}</td>
    </tr>
  </table>

  <!-- GUEST INFORMATION -->
  <div class="section-title">Guest Information</div>
  <table class="info-table" cellpadding="0" cellspacing="0">
    <colgroup>
      <col style="width:22%" /><col style="width:28%" />
      <col style="width:22%" /><col style="width:28%" />
    </colgroup>
    <tr>
      <td class="info-key">Guest Name</td>
      <td class="info-val">{{ reservation.primary_guest_name or '&mdash;' }}</td>
      <td class="info-key">Email Address</td>
      <td class="info-val">{{ reservation.primary_guest_email or '&mdash;' }}</td>
    </tr>
    <tr>
      <td class="info-key">Phone Number</td>
      <td class="info-val">{{ reservation.primary_guest_phone or '&mdash;' }}</td>
      <td class="info-key">Source Channel</td>
      <td class="info-val">{{ reservation.source_channel or '&mdash;' }}</td>
    </tr>
  </table>

  <!-- ROOM ALLOCATION -->
  <div class="section-title">Room Allocation &mdash; {{ reservation.rooms | length }} room{% if reservation.rooms | length != 1 %}s{% endif %}</div>
  {% if reservation.rooms %}
  <table class="rooms-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th style="width:4%;">#</th>
        <th>Room</th>
        <th>Room Type</th>
        <th>Occupant</th>
        <th class="num">Rate / Night</th>
        <th class="num">Room Total</th>
      </tr>
    </thead>
    <tbody>
      {% for room in reservation.rooms %}
      <tr>
        <td style="color:#9ca3af;">{{ loop.index }}</td>
        <td style="font-weight:700;">{{ room.room_number or '&mdash;' }}</td>
        <td>{{ room.room_type or '&mdash;' }}</td>
        <td style="color:#6b7280;">{{ room.occupant_name or reservation.primary_guest_name or '&mdash;' }}</td>
        <td class="num">&#x20a6;{{ "{:,.0f}".format(room.rate_per_night | float) }}</td>
        <td class="num" style="font-weight:600;">&#x20a6;{{ "{:,.0f}".format(room.room_total | float) }}</td>
      </tr>
      {% endfor %}
    </tbody>
    <tfoot>
      <tr>
        <td colspan="5">Subtotal</td>
        <td class="num">&#x20a6;{{ "{:,.0f}".format(reservation.subtotal | float) }}</td>
      </tr>
    </tfoot>
  </table>
  {% else %}
  <p style="padding:14px;color:#9ca3af;font-size:8pt;border:1px dashed #e5e7eb;">No room allocations on this reservation.</p>
  {% endif %}

  <!-- PAYMENT SUMMARY -->
  <div class="section-title">Payment Summary</div>
  <table class="payment-table" cellpadding="0" cellspacing="0">
    <tr>
      <td class="p-label">Subtotal</td>
      <td class="p-value">&#x20a6;{{ "{:,.0f}".format(reservation.subtotal | float) }}</td>
    </tr>
    {% if reservation.discount_amount and reservation.discount_amount | float > 0 %}
    <tr>
      <td class="p-label">Discount</td>
      <td class="p-value">&minus; &#x20a6;{{ "{:,.0f}".format(reservation.discount_amount | float) }}</td>
    </tr>
    {% endif %}
    <tr class="total-row">
      <td>Total Amount</td>
      <td style="text-align:right;">&#x20a6;{{ "{:,.0f}".format(reservation.total_amount | float) }}</td>
    </tr>
    {% if (reservation.payment_status or '') | lower == 'paid' %}
    <tr class="paid-row">
      <td>&#10003; Payment Received in Full</td>
      <td style="text-align:right;">&#x20a6;{{ "{:,.0f}".format(reservation.total_amount | float) }}</td>
    </tr>
    {% endif %}
  </table>

  <!-- BOOKING NOTES -->
  {% if reservation.booking_notes %}
  <div class="section-title">Notes &amp; Requests</div>
  <div class="notes-box">
    <div class="notes-label">Booking Notes</div>
    {{ reservation.booking_notes }}
  </div>
  {% endif %}

  <!-- FOOTER -->
  <hr class="footer-divider" />
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="60%" valign="bottom">
        <div class="footer-note">
          This confirmation is generated by the {{ company }} Property Management System.<br>
          For queries please contact the reservations desk with your booking reference.<br>
          <strong style="color:#374151;">Booking Reference: {{ reservation.name }}</strong>
        </div>
      </td>
      <td valign="bottom" align="right">
        <div class="footer-company">{{ company }}</div>
        <div class="footer-date">{{ generated_at }}</div>
        <div class="sig-line">Authorised Signature</div>
      </td>
    </tr>
  </table>

</div>
</body>
</html>"}
